from typing import List

def groupAnagrams(strs: List[str]) -> List[List[str]]:
    anagrams = []
    used = [False] * len(strs)

    for i in range(len(strs)):
        if used[i]:
            continue
        group = [strs[i]]
        used[i] = True
        sorted_str_i = ''.join(sorted(strs[i]))

        for j in range(i + 1, len(strs)):
            if not used[j] and ''.join(sorted(strs[j])) == sorted_str_i:
                group.append(strs[j])
                used[j] = True

        anagrams.append(group)

    return anagrams

